const input = $input.first().json;
const query = input.query ?? input;

const esc = (value) => String(value).replace(/'/g, "''");
const nullableTimestamp = (value) => {
  if (!value) return 'NULL';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) throw new Error(`Invalid datetime: ${value}`);
  return `'${esc(String(value).replace(/Z$/, ''))}'`;
};

const VALID_STATUS = ['pending', 'done', 'dismissed', 'cancelled'];
const status = query.status ? String(query.status).toLowerCase().trim() : null;
if (status && !VALID_STATUS.includes(status)) throw new Error(`Invalid status: ${query.status}`);

const includeCancelled = ['true', '1', 'yes'].includes(String(query.include_cancelled ?? '').toLowerCase());

return [{ json: {
  from_sql: nullableTimestamp(query.from),
  to_sql: nullableTimestamp(query.to),
  status_sql: status ? `'${esc(status)}'` : 'NULL',
  include_cancelled: includeCancelled,
} }];
